"use strict";
// vendor-manifest-load-smoke (Track C): prove the GENERATED per-vendor mcp.json
// files actually BOOT a working MCP server — not just that they match source bytes.
//
// `gen-manifests --check` only diffs generated bytes against the manifest source,
// and `parity-check` boots dist/mcp-server.js directly — neither ever loads a
// vendor's mcp.json the way that client would. So a manifest could declare a wrong
// command/args/path and every gate would still pass. This smoke closes that: for
// every vendor in manifest/plugin.manifest.json `targets` that declares an `mcp`
// output, it reads the generated mcp.json, resolves the server command+args exactly
// as that client does (substituting the vendor's pluginRootVar to the real plugin
// root), spawns it with shell:false, and asserts a JSON-RPC initialize + tools/list
// round-trip. All vendors run the same kernel, so they must agree on serverInfo and
// the tool count — divergence means a vendor manifest drifted from a bootable shape.

const assert = require("node:assert/strict");
const fs = require("node:fs");
const path = require("node:path");
const readline = require("node:readline");
const { spawn } = require("node:child_process");

const node = process.execPath;
const pluginRoot = path.resolve(__dirname, ".."); // plugins/cool-workflow
const repoRoot = path.resolve(pluginRoot, "..", ".."); // worktree/repo root
const manifest = require(path.join(pluginRoot, "manifest", "plugin.manifest.json"));
const serverName = manifest.mcp && manifest.mcp.serverName ? manifest.mcp.serverName : "cool-workflow";

function vendorsWithMcp() {
  const targets = manifest.targets || {};
  return Object.entries(targets)
    .filter(([, t]) => t && typeof t.mcp === "string")
    .map(([id, t]) => ({ id, mcpPath: path.join(repoRoot, t.mcp), pluginRootVar: t.pluginRootVar || "./" }));
}

// Resolve one mcp.json arg the way the client does: a leading pluginRootVar
// (`${CLAUDE_PLUGIN_ROOT}/` or `./`) expands to the real plugin root.
function resolveArg(arg, pluginRootVar) {
  if (typeof arg !== "string") return String(arg);
  if (arg.startsWith(pluginRootVar)) return path.join(pluginRoot, arg.slice(pluginRootVar.length));
  return arg;
}

function bootAndHandshake(vendor) {
  const config = JSON.parse(fs.readFileSync(vendor.mcpPath, "utf8"));
  const servers = config.mcpServers || {};
  const server = servers[serverName];
  assert.ok(server, `${vendor.id}: mcp.json declares an "${serverName}" server`);
  assert.equal(server.command, "node", `${vendor.id}: server command is node`);
  const args = (server.args || []).map((a) => resolveArg(a, vendor.pluginRootVar));
  assert.ok(args.length > 0, `${vendor.id}: server has args`);
  assert.ok(fs.existsSync(args[0]), `${vendor.id}: resolved server script exists (${args[0]})`);

  return new Promise((resolve, reject) => {
    // shell:false (argv spawn) exactly as an MCP client launches it. cwd + the
    // CLAUDE_PLUGIN_ROOT env mirror the client environment, though the args are
    // already resolved to an absolute path.
    const proc = spawn(node, args, {
      cwd: pluginRoot,
      stdio: ["pipe", "pipe", "pipe"],
      env: { ...process.env, CLAUDE_PLUGIN_ROOT: pluginRoot }
    });
    const lines = readline.createInterface({ input: proc.stdout });
    const pending = new Map();
    let nextId = 1;
    const timer = setTimeout(() => {
      proc.kill();
      reject(new Error(`${vendor.id}: MCP handshake timed out`));
    }, 20000);
    lines.on("line", (line) => {
      let msg;
      try { msg = JSON.parse(line); } catch { return; }
      const w = pending.get(msg.id);
      if (!w) return;
      pending.delete(msg.id);
      msg.error ? w.reject(new Error(msg.error.message)) : w.resolve(msg.result);
    });
    const rpc = (method, params) => {
      const id = nextId++;
      proc.stdin.write(`${JSON.stringify({ jsonrpc: "2.0", id, method, params })}\n`);
      return new Promise((res, rej) => pending.set(id, { resolve: res, reject: rej }));
    };
    (async () => {
      const init = await rpc("initialize", {});
      const list = await rpc("tools/list", {});
      clearTimeout(timer);
      proc.kill();
      resolve({
        vendor: vendor.id,
        serverInfoName: init && init.serverInfo ? init.serverInfo.name : undefined,
        toolCount: list && Array.isArray(list.tools) ? list.tools.length : -1
      });
    })().catch((e) => { clearTimeout(timer); proc.kill(); reject(e); });
  });
}

(async () => {
  const vendors = vendorsWithMcp();
  assert.ok(vendors.length >= 2, `Track C needs >=2 vendor mcp manifests (found ${vendors.length})`);

  const results = [];
  for (const v of vendors) results.push(await bootAndHandshake(v));

  // Every generated manifest must boot to the SAME kernel: same serverInfo name and
  // identical tool count (they all launch dist/mcp-server.js).
  const names = new Set(results.map((r) => r.serverInfoName));
  const counts = new Set(results.map((r) => r.toolCount));
  for (const r of results) {
    assert.ok(r.serverInfoName, `${r.vendor}: initialize returned a serverInfo.name`);
    assert.ok(r.toolCount > 0, `${r.vendor}: tools/list returned tools (${r.toolCount})`);
  }
  assert.equal(names.size, 1, `all vendors agree on serverInfo.name (${[...names].join(", ")})`);
  assert.equal(counts.size, 1, `all vendors expose the same tool count (${[...counts].join(", ")})`);

  process.stdout.write(
    `vendor-manifest-load-smoke: ok (${results.length} vendor manifests booted — ${[...names][0]}, ${[...counts][0]} tools each: ${results.map((r) => r.vendor).join(", ")})\n`
  );
})().catch((e) => {
  process.stderr.write(`vendor-manifest-load-smoke: FAIL ${e.message}\n`);
  process.exit(1);
});
